<?php
declare(strict_types=1);
require dirname(__DIR__) . '/bootstrap.php';
$admin=vp3_require_admin_permission('network.manage');$id=(int)vp3_input('id');
if(vp3_method()==='POST'){
    vp3_verify_csrf();$licenseId=(int)vp3_input('license_id');$license=vp3_db()->prepare('SELECT l.id,l.customer_id,l.product_id,l.edition FROM licenses l WHERE l.id=? AND l.status IN (\'active\',\'development\') LIMIT 1');$license->execute([$licenseId]);$license=$license->fetch();if(!$license)throw new RuntimeException('active_license_required');$domain=vp3_normalize_domain(vp3_input('public_domain'));$domainCheck=vp3_db()->prepare("SELECT COUNT(*) FROM license_domains WHERE license_id=? AND status='active' AND (domain=? OR domain='*')");$domainCheck->execute([$licenseId,$domain]);if((int)$domainCheck->fetchColumn()<1)throw new RuntimeException('domain_not_authorized_for_license');$hostingId=(int)vp3_input('hosting_account_id');if($hostingId<1)$hostingId=null;$creatorId=(int)vp3_input('creator_id');if($creatorId<1)$creatorId=null;$showId=(int)vp3_input('show_id');if($showId<1)$showId=null;if($hostingId!==null){$check=vp3_db()->prepare('SELECT COUNT(*) FROM hosting_accounts WHERE id=? AND customer_id=? AND product_id=?');$check->execute([$hostingId,(int)$license['customer_id'],(int)$license['product_id']]);if((int)$check->fetchColumn()<1)throw new RuntimeException('hosting_customer_product_mismatch');}if($creatorId!==null){$check=vp3_db()->prepare('SELECT COUNT(*) FROM creators WHERE id=? AND customer_id=?');$check->execute([$creatorId,(int)$license['customer_id']]);if((int)$check->fetchColumn()<1)throw new RuntimeException('creator_customer_mismatch');}if($showId!==null){$check=vp3_db()->prepare('SELECT COUNT(*) FROM shows WHERE id=? AND customer_id=?');$check->execute([$showId,(int)$license['customer_id']]);if((int)$check->fetchColumn()<1)throw new RuntimeException('show_customer_mismatch');}$name=vp3_input('display_name');$slug=preg_replace('/[^a-z0-9-]/','',strtolower(vp3_input('slug')))?:'';if($name===''||$slug===''||$domain==='')throw new RuntimeException('platform_identity_required');$verification= strtoupper(vp3_input('verification_id'));if($verification==='')$verification='VP3-VRF-'.strtoupper(substr(bin2hex(random_bytes(8)),0,12));$data=[(int)$license['customer_id'],(int)$license['product_id'],$licenseId,$hostingId,$creatorId,$showId,$name,$slug,vp3_input('description'),$domain,vp3_input('hosting_type'),$verification,vp3_input('verification_status'),vp3_input('listing_status'),vp3_input('auto_publish_clips')==='1'?1:0,max(0,(int)vp3_input('featured_rank')),vp3_input('launched_at')?:null];if($id>0){$stmt=vp3_db()->prepare('UPDATE public_platform_listings SET customer_id=?,product_id=?,license_id=?,hosting_account_id=?,creator_id=?,show_id=?,display_name=?,slug=?,description=?,public_domain=?,hosting_type=?,verification_id=?,verification_status=?,listing_status=?,auto_publish_clips=?,featured_rank=?,launched_at=?,updated_at=NOW() WHERE id=?');$stmt->execute([...$data,$id]);$uuid=(string)vp3_db()->query('SELECT listing_uuid FROM public_platform_listings WHERE id='.(int)$id)->fetchColumn();}else{$uuid=vp3_uuid();$stmt=vp3_db()->prepare('INSERT INTO public_platform_listings (listing_uuid,customer_id,product_id,license_id,hosting_account_id,creator_id,show_id,display_name,slug,description,public_domain,hosting_type,verification_id,verification_status,listing_status,auto_publish_clips,featured_rank,launched_at,created_at,updated_at) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,NOW(),NOW())');$stmt->execute([$uuid,...$data]);$id=(int)vp3_db()->lastInsertId();}vp3_audit('admin',(int)$admin['id'],'public_platform.saved','public_platform',$uuid,['id'=>$id,'verification_id'=>$verification]);vp3_flash('success','Public platform saved.');vp3_redirect('admin/public-listing.php?id='.$id);}
$row=null;if($id>0){$s=vp3_db()->prepare('SELECT * FROM public_platform_listings WHERE id=?');$s->execute([$id]);$row=$s->fetch();if(!$row){http_response_code(404);exit('Platform not found.');}}
$licenses=vp3_db()->query("SELECT l.id,l.customer_id,l.product_id,l.edition,l.license_key_prefix,c.name customer_name,p.name product_name FROM licenses l JOIN customers c ON c.id=l.customer_id JOIN products p ON p.id=l.product_id WHERE l.status IN ('active','development') ORDER BY l.id DESC")->fetchAll();$hosting=vp3_db()->query("SELECT id,customer_id,subdomain,custom_domain FROM hosting_accounts WHERE hosting_status IN ('pending','active') ORDER BY id DESC")->fetchAll();$creators=vp3_db()->query('SELECT id,customer_id,display_name FROM creators ORDER BY display_name')->fetchAll();$shows=vp3_db()->query('SELECT id,customer_id,title FROM shows ORDER BY title')->fetchAll();$pageTitle=$row?'Edit Public Platform':'Register Public Platform';require VP3_ROOT.'/includes/admin-header.php';
?>
<div class="admin-page-head"><div><span class="admin-kicker">VP3 Network</span><h1><?=vp3_e($pageTitle)?></h1></div><a class="button secondary" href="public-listings.php">Back to platforms</a></div><form method="post" class="card admin-form"><?=vp3_csrf_field()?><div class="admin-form-grid"><div class="field full"><label>Active license</label><select name="license_id" required><option value="">Select</option><?php foreach($licenses as $l):?><option value="<?=(int)$l['id']?>" <?= (int)($row['license_id']??0)===(int)$l['id']?'selected':'' ?>><?=vp3_e($l['customer_name'].' · '.$l['product_name'].' · '.$l['edition'].' · '.$l['license_key_prefix'])?></option><?php endforeach;?></select></div><div class="field"><label>Display name</label><input name="display_name" value="<?=vp3_e($row['display_name']??'')?>" required></div><div class="field"><label>Slug</label><input name="slug" pattern="[a-z0-9-]+" value="<?=vp3_e($row['slug']??'')?>" required></div><div class="field full"><label>Description</label><textarea name="description"><?=vp3_e($row['description']??'')?></textarea></div><div class="field"><label>Public domain</label><input name="public_domain" value="<?=vp3_e($row['public_domain']??'')?>" required></div><div class="field"><label>Hosting type</label><select name="hosting_type"><?php foreach(['self_hosted','vp3_hosted'] as $v):?><option <?=($row['hosting_type']??'vp3_hosted')===$v?'selected':''?>><?=$v?></option><?php endforeach;?></select></div><div class="field"><label>Hosting account</label><select name="hosting_account_id"><option value="0">None</option><?php foreach($hosting as $h):?><option value="<?=(int)$h['id']?>" <?= (int)($row['hosting_account_id']??0)===(int)$h['id']?'selected':'' ?>><?=vp3_e($h['subdomain']?:$h['custom_domain'])?></option><?php endforeach;?></select></div><div class="field"><label>Creator</label><select name="creator_id"><option value="0">None</option><?php foreach($creators as $c):?><option value="<?=(int)$c['id']?>" <?= (int)($row['creator_id']??0)===(int)$c['id']?'selected':'' ?>><?=vp3_e($c['display_name'])?></option><?php endforeach;?></select></div><div class="field"><label>Show</label><select name="show_id"><option value="0">None</option><?php foreach($shows as $s):?><option value="<?=(int)$s['id']?>" <?= (int)($row['show_id']??0)===(int)$s['id']?'selected':'' ?>><?=vp3_e($s['title'])?></option><?php endforeach;?></select></div><div class="field"><label>Verification ID</label><input name="verification_id" value="<?=vp3_e($row['verification_id']??'')?>" placeholder="Generated when blank"></div><div class="field"><label>Verification status</label><select name="verification_status"><?php foreach(['pending','verified','suspended','revoked'] as $v):?><option <?=($row['verification_status']??'pending')===$v?'selected':''?>><?=$v?></option><?php endforeach;?></select></div><div class="field"><label>Listing status</label><select name="listing_status"><?php foreach(['draft','published','hidden','archived'] as $v):?><option <?=($row['listing_status']??'draft')===$v?'selected':''?>><?=$v?></option><?php endforeach;?></select></div><div class="field"><label>Featured rank</label><input name="featured_rank" type="number" min="0" value="<?=vp3_e($row['featured_rank']??0)?>"></div><div class="field"><label>Launch date</label><input name="launched_at" type="date" value="<?=vp3_e(isset($row['launched_at'])?substr((string)$row['launched_at'],0,10):'')?>"></div></div><label class="check-row"><input type="checkbox" name="auto_publish_clips" value="1" <?=!empty($row['auto_publish_clips'])?'checked':''?>> Auto-approve rights-confirmed clips from this platform</label><button class="button">Save platform</button></form>
<?php require VP3_ROOT.'/includes/admin-footer.php';?>
